import { useState, useEffect, useRef, useCallback } from 'react';

export const useProgressQueue = (duration = 3000) => {
    // We use state to trigger UI updates
    const [displayQueue, setDisplayQueue] = useState([]);

    // We use Refs for the "Engine" logic to avoid stale closures
    const queueRef = useRef([]);
    const activeIndexRef = useRef(0);
    const requestRef = useRef();
    const startTimeRef = useRef(null);
    const isAnimatingRef = useRef(false);

    const animate = useCallback((time) => {
        if (startTimeRef.current === null) {
            startTimeRef.current = time;
        }

        const elapsed = time - startTimeRef.current;
        const progress = Math.min((elapsed / duration) * 100, 100);

        // 1. Update the "Source of Truth" (Ref)
        queueRef.current[activeIndexRef.current] = progress;

        // 2. Sync to State so React renders the change
        setDisplayQueue([...queueRef.current]);

        if (progress < 100) {
            requestRef.current = requestAnimationFrame(animate);
        } else {
            // Bar finished: Clean up and check for next
            cancelAnimationFrame(requestRef.current);
            startTimeRef.current = null;
            activeIndexRef.current += 1;
            isAnimatingRef.current = false;

            // Trigger next bar if it exists
            if (activeIndexRef.current < queueRef.current.length) {
                startNextAnimation();
            }
        }
    }, [duration]);

    const startNextAnimation = useCallback(() => {
        if (!isAnimatingRef.current && activeIndexRef.current < queueRef.current.length) {
            isAnimatingRef.current = true;
            requestRef.current = requestAnimationFrame(animate);
        }
    }, [animate]);

    const addBar = useCallback(() => {
        // Add to the Ref and the State simultaneously
        queueRef.current.push(0);
        setDisplayQueue([...queueRef.current]);

        // Attempt to start the engine
        startNextAnimation();
    }, [startNextAnimation]);

    // Cleanup on unmount
    useEffect(() => {
        return () => cancelAnimationFrame(requestRef.current);
    }, []);

    return { queue: displayQueue, addBar };
};
